            rows.push('<th scope="col">Client</th>');
            rows.push('<th scope="col">Phone</th>');
            rows.push('<th scope="col">Email</th>');
            rows.push('<th scope="col">Registered</th>');
            rows.push('<th scope="col" style="text-align: right;">');
            
